import{_ as a,c as t,o as s,ae as n}from"./chunks/framework.Cd-3tpCq.js";const h=JSON.parse(`{"title":"Étape 6.1 — Créer un Pattern depuis l'UI Canvas","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-canvas/patterns-create.md","filePath":"drupal-canvas/patterns-create.md"}`),r={name:"drupal-canvas/patterns-create.md"};function i(o,e,l,c,p,u){return s(),t("div",null,e[0]||(e[0]=[n(`<h1 id="etape-6-1-—-creer-un-pattern-depuis-l-ui-canvas" tabindex="-1">Étape 6.1 — Créer un Pattern depuis l&#39;UI Canvas <a class="header-anchor" href="#etape-6-1-—-creer-un-pattern-depuis-l-ui-canvas" aria-label="Permalink to &quot;Étape 6.1 — Créer un Pattern depuis l&#39;UI Canvas&quot;">​</a></h1><h2 id="qu-est-ce-qu-un-pattern" tabindex="-1">Qu&#39;est-ce qu&#39;un Pattern ? <a class="header-anchor" href="#qu-est-ce-qu-un-pattern" aria-label="Permalink to &quot;Qu&#39;est-ce qu&#39;un Pattern ?&quot;">​</a></h2><p>Un <strong>Pattern</strong> est un assemblage de composants SDC que vous sauvegardez depuis l&#39;interface Canvas pour le <strong>réutiliser facilement</strong> sur d&#39;autres pages.</p><p>Imaginez que vous avez construit une section &quot;Services&quot; avec un Grid + 3 Cards. Plutôt que de reconstruire cette mise en page à chaque nouvelle page, vous la sauvegardez comme Pattern. Il apparaît alors dans la bibliothèque, prêt à être utilisé en un clic.</p><div class="tip custom-block"><p class="custom-block-title">Analogie</p><p>Un Pattern, c&#39;est comme un <strong>bloc LEGO déjà assemblé</strong> que vous mettez de côté pour le réutiliser. Les SDC sont les briques individuelles, les Patterns sont des constructions pré-fabriquées.</p></div><h2 id="creer-un-pattern-section-services" tabindex="-1">Créer un Pattern &quot;Section Services&quot; <a class="header-anchor" href="#creer-un-pattern-section-services" aria-label="Permalink to &quot;Créer un Pattern &quot;Section Services&quot;&quot;">​</a></h2><h3 id="etape-1-—-construire-l-assemblage-dans-canvas" tabindex="-1">Étape 1 — Construire l&#39;assemblage dans Canvas <a class="header-anchor" href="#etape-1-—-construire-l-assemblage-dans-canvas" aria-label="Permalink to &quot;Étape 1 — Construire l&#39;assemblage dans Canvas&quot;">​</a></h3><p>Ouvrez n&#39;importe quelle Canvas Page dans l&#39;éditeur et construisez la mise en page que vous souhaitez sauvegarder.</p><p>Exemple — Section Services :</p><ol><li>Ajoutez une section</li><li>Placez un composant <strong>Grid</strong> (3 colonnes, titre &quot;Nos Services&quot;)</li><li>Ajoutez 3 composants <strong>Card</strong> avec des valeurs d&#39;exemple</li></ol><h3 id="etape-2-—-selectionner-la-section-a-sauvegarder" tabindex="-1">Étape 2 — Sélectionner la section à sauvegarder <a class="header-anchor" href="#etape-2-—-selectionner-la-section-a-sauvegarder" aria-label="Permalink to &quot;Étape 2 — Sélectionner la section à sauvegarder&quot;">​</a></h3><ol><li>Cliquez sur la section entière (cliquez sur le bord/l&#39;en-tête de section, pas sur un composant)</li><li>Un contour orange entoure la section sélectionnée</li><li>Dans la barre d&#39;actions de la section, cliquez sur l&#39;icône <strong>Sauvegarder comme Pattern</strong> (📋 ou similaire)</li></ol><h3 id="etape-3-—-nommer-le-pattern" tabindex="-1">Étape 3 — Nommer le Pattern <a class="header-anchor" href="#etape-3-—-nommer-le-pattern" aria-label="Permalink to &quot;Étape 3 — Nommer le Pattern&quot;">​</a></h3><p>Une fenêtre s&#39;ouvre :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────┐</span></span>
<span class="line"><span>│  Sauvegarder comme Pattern         │</span></span>
<span class="line"><span>├────────────────────────────────────┤</span></span>
<span class="line"><span>│  Nom : [Section Services      ]    │</span></span>
<span class="line"><span>│  Catégorie : [Sections        ▼]   │</span></span>
<span class="line"><span>│  Description : [_____________ ]    │</span></span>
<span class="line"><span>│                                    │</span></span>
<span class="line"><span>│  [ Annuler ]    [ Sauvegarder ]    │</span></span>
<span class="line"><span>└────────────────────────────────────┘</span></span></code></pre></div><p>Renseignez :</p><ul><li><strong>Nom</strong> : <code>Section Services</code></li><li><strong>Catégorie</strong> : <code>Sections</code> (ou créez-en une nouvelle)</li><li><strong>Description</strong> : <code>Grille 3 colonnes avec Cards icônes/titre/texte</code></li></ul><p>Cliquez sur <strong>Sauvegarder</strong>.</p><h2 id="le-pattern-est-maintenant-disponible" tabindex="-1">Le Pattern est maintenant disponible <a class="header-anchor" href="#le-pattern-est-maintenant-disponible" aria-label="Permalink to &quot;Le Pattern est maintenant disponible&quot;">​</a></h2><p>Dans le panneau gauche de Canvas, onglet <strong>Patterns</strong>, votre nouveau Pattern apparaît sous la catégorie choisie.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Panneau gauche → Patterns → Sections → Section Services</span></span></code></pre></div><h2 id="autres-patterns-utiles-a-creer" tabindex="-1">Autres Patterns utiles à créer <a class="header-anchor" href="#autres-patterns-utiles-a-creer" aria-label="Permalink to &quot;Autres Patterns utiles à créer&quot;">​</a></h2><p>Voici des assemblages courants que vous pouvez sauvegarder comme Patterns :</p><table tabindex="0"><thead><tr><th>Nom du Pattern</th><th>Contenu</th></tr></thead><tbody><tr><td><code>Section Services</code></td><td>Grid 3 colonnes + 3 Cards icônes</td></tr><tr><td><code>Section À propos</code></td><td>Grid 2 colonnes (image + texte)</td></tr><tr><td><code>Page intérieure</code></td><td>Page Header + Grid contenu/sidebar</td></tr><tr><td><code>CTA Banner</code></td><td>Hero mini centré + bouton</td></tr><tr><td><code>Section Témoignages</code></td><td>Grid 3 colonnes + Cards texte + auteur</td></tr><tr><td><code>Section Équipe</code></td><td>Grid 4 colonnes + Cards photo + nom + poste</td></tr></tbody></table><h2 id="modifier-un-pattern-existant" tabindex="-1">Modifier un Pattern existant <a class="header-anchor" href="#modifier-un-pattern-existant" aria-label="Permalink to &quot;Modifier un Pattern existant&quot;">​</a></h2><p>Les Patterns ne sont <strong>pas dynamiques</strong> : modifier un Pattern ne met pas à jour les pages où il est déjà utilisé. Un Pattern est une copie de l&#39;assemblage au moment de la sauvegarde.</p><p>Pour modifier un Pattern :</p><ol><li>Trouvez une page où ce Pattern est utilisé</li><li>Modifiez l&#39;assemblage</li><li>Sauvegardez comme <strong>nouveau Pattern</strong> (ou remplacez l&#39;ancien)</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Supprimer un Pattern n&#39;affecte pas les pages où il a déjà été utilisé. La suppression ne concerne que la disponibilité dans la bibliothèque.</p></div><h2 id="ou-sont-stockes-les-patterns" tabindex="-1">Où sont stockés les Patterns ? <a class="header-anchor" href="#ou-sont-stockes-les-patterns" aria-label="Permalink to &quot;Où sont stockés les Patterns ?&quot;">​</a></h2><p>Les Patterns sont stockés en <strong>configuration Drupal</strong> (table <code>config</code>). Vous pouvez donc les exporter/importer avec les commandes habituelles :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Exporter la configuration (inclut les Patterns)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">drush</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config:export</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Importer sur un autre environnement</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">drush</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config:import</span></span></code></pre></div><p>Cela vous permet de versionner vos Patterns dans Git et de les déployer d&#39;un environnement à l&#39;autre.</p>`,33)]))}const g=a(r,[["render",i]]);export{h as __pageData,g as default};
